pub fn drawhalf(cpu: &mut Cpu) {
    cpu.reg.a = cpu.mem[sym::PRECED];
    cpu.flags.z = cpu.reg.a == 0;
    cpu.flags.n = (cpu.reg.a >> 7) != 0;
    if cpu.reg.a != 0x00 {
        return;
    }
    'b10: {
        cpu.reg.x = cpu.mem[sym::objid];
        cpu.flags.z = cpu.reg.x == 0;
        cpu.flags.n = (cpu.reg.x >> 7) != 0;
        if cpu.reg.x != 0x01 {
            if cpu.reg.x != 0x13 {
                if cpu.reg.x != 0x05 {
                    if cpu.reg.x != 0x10 {
                        cpu.reg.a = cpu.mem[sym::BGset1];
                        cpu.flags.z = cpu.reg.a == 0;
                        cpu.flags.n = (cpu.reg.a >> 7) != 0;
                        if cpu.reg.a != 0x01 {
                            crate::ext::_5ddrawflr(cpu);
                            return;
                        }
                        if cpu.reg.x != 0x03 {
                            if cpu.reg.x != 0x19 {
                                crate::ext::_5ddrawflr(cpu);
                                return;
                            }
                        }
                        _3asub(cpu);
                        cpu.reg.a = 0x0e;
                        cpu.flags.z = cpu.reg.a == 0;
                        cpu.flags.n = (cpu.reg.a >> 7) != 0;
                        if cpu.reg.a != 0x00 {
                            break 'b10;
                        }
                    }
                }
            }
        }
        _3asub(cpu);
        cpu.reg.a = 0x12;
        cpu.flags.z = cpu.reg.a == 0;
        cpu.flags.n = (cpu.reg.a >> 7) != 0;
    }
    cpu.mem[sym::IMAGE] = cpu.reg.a;
    cpu.reg.a = 0x01;
    cpu.flags.z = cpu.reg.a == 0;
    cpu.flags.n = (cpu.reg.a >> 7) != 0;
    cpu.mem[sym::OPACITY] = cpu.reg.a;
    add(cpu);
    drawd(cpu);
    return;
}

