pub fn wiped(cpu: &mut Cpu) {
    let mut pc: u32 = 0;
    loop {
        match pc {
            0 => {
                cpu.reg.a = cpu.mem[sym::objid];
                cpu.flags.z = cpu.reg.a == 0;
                cpu.flags.n = (cpu.reg.a >> 7) != 0;
                if cpu.reg.a == 0x09 {
                    pc = 5;
                } else {
                    pc = 1;
                }
            }
            1 => {
                if cpu.reg.a == 0x07 {
                    pc = 5;
                } else {
                    pc = 2;
                }
            }
            2 => {
                if cpu.reg.a == 0x0c {
                    pc = 5;
                } else {
                    pc = 3;
                }
            }
            3 => {
                let _o: u8 = 0x14;
                cpu.flags.c = cpu.reg.a >= _o;
                cpu.flags.z = cpu.reg.a == _o;
                cpu.flags.n = (cpu.reg.a.wrapping_sub(_o) >> 7) != 0;
                if cpu.reg.a == 0x14 {
                    pc = 5;
                } else {
                    pc = 4;
                }
            }
            4 => {
                cpu.reg.a = 0x03;
                cpu.flags.z = cpu.reg.a == 0;
                cpu.flags.n = (cpu.reg.a >> 7) != 0;
                crate::ext::_5dwipe(cpu);
                return;
            }
            5 => {
                return;
            }
            _ => unreachable!(),
        }
    }
}

