    cpu.flags.n = (cpu.reg.x >> 7) != 0;
    cpu.mem[sym::IMAGE] = cpu.mem[sym::pieceb + cpu.reg.x as usize];
    cpu.reg.a = cpu.mem[sym::pieceby + cpu.reg.x as usize];
