pub fn drawobjx(cpu: &mut Cpu) {
    loadobj(cpu);
    if cpu.reg.a == 0x00 {
        crate::ext::DrawKid(cpu);
        return;
    }
    if cpu.reg.a != 0x04 {
        if cpu.reg.a != 0x01 {
            if cpu.reg.a != 0x80 {
                if cpu.reg.a == 0x03 {
                    crate::ext::DrawSword(cpu);
                    return;
                }
                if cpu.reg.a != 0x05 {
                    if cpu.reg.a != 0x02 {
                        return;
                    }
                    crate::ext::DrawGuard(cpu);
                    return;
                }
                crate::ext::DrawSword(cpu);
                return;
            }
            DrawFF(cpu);
            return;
        }
        crate::ext::DrawShad(cpu);
        return;
    }
    crate::ext::DrawKid(cpu);
    return;
}

